import argparse
import json
import os
import numpy as np
from cogniplan_env import ExplorationEnv
import heapq
import torch


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = tuple(np.round(n["coords"], 6))
        coord_to_idx[coord] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(tuple(np.round(nb, 6)))
            else:
                j = int(nb) if (0 <= int(nb) < N) else None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        j = coord_to_idx.get(tuple(np.round(nb, 6)))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class Explorer:
    def __init__(self):
        self.step_count = 0
        self.history = []
        self.prev_pos = None
        self.prev_move_dir = None

    def _update_history(self, coord):
        self.history.append(np.array(coord, dtype=float))
        if len(self.history) > 20:
            self.history.pop(0)

    def select_action(self, obs):
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        self.step_count += 1
        steps_remaining = max(0, 128 - self.step_count)

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        # first_step[j] = first graph node on shortest path from robot to j
        first_step = [None] * N
        order = [i for i in range(N) if dist[i] < float('inf') and i != r_idx]
        order.sort(key=lambda i: dist[i])
        for j in order:
            p = prev[j]
            if p == r_idx:
                first_step[j] = j
            else:
                fs = first_step[p] if p is not None else None
                first_step[j] = fs if fs is not None else j

        # map node index -> neighbor list index
        node_to_neighbor_idx = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(tuple(np.round(nb, 6)))
            if j is not None:
                node_to_neighbor_idx[j] = idx

        scores = np.zeros(len(neighbors), dtype=float)
        history_set = set(tuple(np.round(h, 6)) for h in self.history)

        for j in range(N):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf') or d < 1e-6:
                continue
            fs = first_step[j]
            if fs is None:
                continue
            nb_idx = node_to_neighbor_idx.get(fs)
            if nb_idx is None:
                continue

            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue

            val = utility / (d + 3.6)

            if bool(nodes[j].get("visited", False)):
                val *= 0.2

            coord_j = tuple(np.round(nodes[j]["coords"], 6))
            if coord_j in history_set:
                val *= 0.65

            est_steps = d / 3.2
            if est_steps > steps_remaining:
                val = 0.0
            elif est_steps > steps_remaining * 0.75:
                val *= 0.25

            scores[nb_idx] += val

        # Fallback when no aggregated utility
        if np.max(scores) < 1e-9:
            if frontiers and len(frontiers) > 0:
                frontier_arr = np.array(frontiers, dtype=float)
                best_idx = None
                best_dist = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_arr = np.array(nb, dtype=float).reshape(1, -1)
                    dists = np.linalg.norm(frontier_arr - nb_arr, axis=1)
                    min_d = np.min(dists)
                    if min_d < best_dist:
                        best_dist = min_d
                        best_idx = idx
                if best_idx is not None:
                    scores[best_idx] = 1.0
                else:
                    scores[:] = 1.0 / len(neighbors)
            else:
                # Prefer unvisited neighbor nodes
                unvisited_idxs = []
                for idx, nb in enumerate(neighbors):
                    j = coord_to_idx.get(tuple(np.round(nb, 6)))
                    if j is not None and not bool(nodes[j].get("visited", False)):
                        unvisited_idxs.append(idx)
                if unvisited_idxs:
                    for idx in unvisited_idxs:
                        scores[idx] = 1.0
                else:
                    if self.history:
                        hist_arr = np.array(self.history, dtype=float)
                        best_idx = None
                        best_dist = -1.0
                        for idx, nb in enumerate(neighbors):
                            nb_arr = np.array(nb, dtype=float).reshape(1, -1)
                            dists = np.linalg.norm(hist_arr - nb_arr, axis=1)
                            min_d = np.min(dists)
                            if min_d > best_dist:
                                best_dist = min_d
                                best_idx = idx
                        if best_idx is not None:
                            scores[best_idx] = 1.0
                        else:
                            scores[:] = 1.0 / len(neighbors)
                    else:
                        scores[:] = 1.0 / len(neighbors)

        # Anti-backtracking / momentum
        if self.prev_pos is not None and self.prev_move_dir is not None:
            move_dir = self.prev_move_dir
            move_norm = np.linalg.norm(move_dir)
            if move_norm > 0.01:
                for idx, nb in enumerate(neighbors):
                    nb_dir = np.array(nb, dtype=float) - robot_pos
                    nb_norm = np.linalg.norm(nb_dir)
                    if nb_norm > 0.01:
                        cos_sim = np.dot(move_dir, nb_dir) / (move_norm * nb_norm)
                        if cos_sim < -0.6:
                            scores[idx] *= 0.2
                        elif cos_sim > 0.7:
                            scores[idx] *= 1.1

        best_idx = int(np.argmax(scores))
        action = tuple(float(x) for x in neighbors[best_idx])

        self._update_history(robot_pos)
        self.prev_pos = robot_pos.copy()
        self.prev_move_dir = np.array(action, dtype=float) - robot_pos
        return action


def run_episode(env, explorer):
    obs = env.reset()
    for step in range(128):
        action = explorer.select_action(obs)
        if action is None:
            break
        obs, info = env.step(action)
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    ckpt = torch.load(ckpt_path, map_location="cpu")
    print("Loaded checkpoint version:", ckpt.get("version", "unknown"))

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    with open(eval_config_path, "r") as f:
        eval_config = json.load(f)

    map_dir = os.path.join(args.data_path, "maps_eval")
    per_episode = []
    per_type = {}
    total_explored = 0.0
    total_distance_success = 0.0
    n_success = 0
    n_total = 0

    for ep in eval_config["episodes"]:
        map_path = os.path.join(map_dir, ep["map_path"])
        env_type = ep["env_type"]
        env = ExplorationEnv(map_path=map_path)
        explorer = Explorer()
        metrics = run_episode(env, explorer)

        success = 1 if metrics["explored_rate"] > 0.9999 else 0
        per_episode.append({
            "map_path": ep["map_path"],
            "env_type": env_type,
            "success": success,
            "travel_distance": metrics["travel_distance"],
            "explored_rate": metrics["explored_rate"]
        })

        if env_type not in per_type:
            per_type[env_type] = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0, "count": 0, "n_success": 0}
        per_type[env_type]["explored_rate"] += metrics["explored_rate"]
        per_type[env_type]["count"] += 1
        per_type[env_type]["success_rate"] += success
        if success:
            per_type[env_type]["travel_distance"] += metrics["travel_distance"]
            per_type[env_type]["n_success"] += 1

        total_explored += metrics["explored_rate"]
        if success:
            total_distance_success += metrics["travel_distance"]
            n_success += 1
        n_total += 1

    explored_rate = total_explored / n_total if n_total > 0 else 0.0
    travel_distance = total_distance_success / n_success if n_success > 0 else 0.0
    success_rate = n_success / n_total if n_total > 0 else 0.0

    for env_type in per_type:
        c = per_type[env_type]["count"]
        s = per_type[env_type]["n_success"]
        per_type[env_type]["explored_rate"] /= c
        per_type[env_type]["success_rate"] = s / c if c > 0 else 0.0
        per_type[env_type]["travel_distance"] = per_type[env_type]["travel_distance"] / s if s > 0 else 0.0
        del per_type[env_type]["count"]
        del per_type[env_type]["n_success"]

    result = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": n_total
    }

    os.makedirs(os.path.dirname(args.output) if os.path.dirname(args.output) else ".", exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)


if __name__ == "__main__":
    main()
